var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>승자로서 카나리아 스쿼드에 대한 평가는?</color>","JPN":"<color=#ffd34c>勝者として、カナリア・スクワッドについての評価は？</color>","ENG":"<color=#ffd34c>As the winning team, what was your impression of Canary Squad?</color>","TWN":"<color=#ffd34c>作為獲勝的一方，你會怎麼評價金絲雀小隊？</color>"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"각자의 기량은 준수했어요. 신예 팀이라고는 믿기지 않았습니다.","JPN":"各々の器量は素晴らしかったです。新設のチームとは信じられないくらいでした。","ENG":"Each member was powerful on their own. I couldn't believe they were rookies.","TWN":"每個人的技術都很優秀，說她們是新銳隊伍，我都有點不敢相信。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"하지만 결국 전술의 차이가 승패를 결정지었다고 생각합니다.","JPN":"ですが、結局は戦術の差が勝敗を決したと思いますね。","ENG":"However, when it comes to battle, it all comes down to tactics.","TWN":"不過我認為是因為戰術的差異而分出勝負的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"리더는 저돌적이어선 안 돼요. 항상 냉철하게 팀 전체를 관조해야죠.","JPN":"リーダーは猪突猛進であってはなりません。いつも冷静にチーム全体を見れないと。","ENG":"Leaders should never be aggressive. They must always take a step back and observe the situation with a cool head.","TWN":"作為隊長不能衝動，必須經常冷靜地審視全隊的狀況。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>발전의 여지가 있다고 보시나요?</color>","JPN":"<color=#ffd34c>発展の見込みはあると思いますか？</color>","ENG":"<color=#ffd34c>Do you think that they have potential?</color>","TWN":"<color=#ffd34c>你認為她們還有發展的餘地嗎？</color>"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"카나리아 스쿼드의 리더는 한눈에 봐도 굉장히 어려 보였습니다.","JPN":"カナリア・スクワッドのリーダーはぱっと見にはとても幼く見えました。","ENG":"Canary Squad's leader looked very young.","TWN":"金絲雀小隊的隊長一看就知道年紀很小。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"마지막에 있었던 판단 미스도 그 나이 또래를 감안하면 이상하지 않아요.","JPN":"最後の判断ミスも、その歳を考えるとおかしくありません。","ENG":"I understand why she made that mistake at the end, considering her age.","TWN":"考慮到她的年齡，她最後的判斷失準也不足為奇。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"그러니 지금은 더 많은 경험을 해 보라고 말해 주고 싶군요.","JPN":"ですが、今はもっと色々な経験をしてみた方がいいと助言したいです。","ENG":"I suggest that she experience many different things first.","TWN":"所以現在我想對她說，多積累一些經驗吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"하하, 어쩌면 그 과정에서 건틀렛보다 더 잘 맞는 진로를 찾을 수 있을지도 모르니까요.","JPN":"はは、もしかしたらその過程で、ガントレットよりも適性の合う職業を見つけられるかもしれませんしね。","ENG":"Ha ha, who knows? Maybe she'll find something that suits her more than the Gauntlet.","TWN":"哈哈，說不定你可以在這個過程中，找到比聖鎧更適合發展的領域。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"또 발작이네. 아까운 핸드폰은 왜 집어던져.","JPN":"また発作か？　スマホもったいないから投げるなよ。","ENG":"Another tantrum. What are you throwing the phone for?","TWN":"又來了。幹嘛要摔手機，摔壞多可惜。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"화가 안 나게 생겼어요?","JPN":"これが怒らないでいられると思うの？","ENG":"Aren't you angry?!","TWN":"我能不生氣嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"본선 진출이 인생 업적인 삼류 팀 주제에 우릴 체험학습 나온 어린애 취급하잖아요.","JPN":"本戦進出しか業績のない三流チームのくせに、私たちを体験学習でもしに来た子どもみたいに言ったのよ。","ENG":"The only thing that moron accomplished in his life was making it to the elimination rounds. He treated us like kids on a field trip!","TWN":"一個人生最大成就就是擠進過決賽的三流隊伍，居然把我們當成來體驗學習的小孩子。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이대로는 <color=#ffd34c>그 여자</color> 이전에 그릴 파티의 바보들에게도 웃음거리가 될 거라고요!","JPN":"このままじゃ、<color=#ffd34c>あの女</color>以前に、グリルパーティーのバカどもの嘲笑の的になるわ！","ENG":"At this rate, we'll be nothing but clowns to those idiots in Grill Party, let alone get to <color=#ffd34c>her</color>!","TWN":"照這樣下去，在見到<color=#ffd34c>那女人</color>之前，我會先淪為格里爾派提那群傻子的笑柄的！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아무튼 졌잖아. 그 삼류 팀에게. 패자는 변명할 권리 없어.","JPN":"負けたのは事実だろ？　その三流チームに。敗者は言い訳する権利すらないんだよ。","ENG":"Well, the fact is that we lost. To those morons. We don't get to make excuses.","TWN":"反正就是輸啦，沒什麼好辯解的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"변명이……!","JPN":"言い訳じゃ……！","ENG":"It's not an exc–","TWN":"才不是辯解……！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그게 실전이었잖아?","JPN":"あれが実戦だったらって考えてみろよ。","ENG":"If that were a real battle...","TWN":"如果那是實戰呢？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"넌 평생 네 분대원들을 사지로 밀어 넣은 폐급 새끼 취급 받았어.","JPN":"あんたは一生、分隊員を死地に追いやったクズ扱いされるほどのことだったんだ。","ENG":"Then you would've been condemned for life, being called a piece of trash who put her teammates' lives at risk.","TWN":"那樣的話，你要當一輩子把小隊員送上死路的廢物嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……라이카, 화났어요?","JPN":"……ライカ、怒っているの？","ENG":"...Are you angry, Laika?","TWN":"……萊卡，你生氣了？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"한 번 진 것 갖고 오두방정 떨길래 속 터져서 그런다, 왜.","JPN":"一度負けたくらいでグダグダ言ってるから、ムカついてさ。","ENG":"No, I'm just tired of you whining over one loss.","TWN":"看你輸了一次就大吐苦水，所以我生氣了，不行嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"얼빵이랑 스키너한테 가서 사과나 해. 억지 부려서 미안했다고.","JPN":"間抜けとスキナーに謝れ。わがまま言って悪かったって。","ENG":"Go and apologize to Skinner and that goon. Tell them you're sorry for being so stubborn.","TWN":"去跟小瓜呆和史金納道歉，說對不起，是你自己太衝動。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"리더 노릇을 하고 싶으면 리더답게 굴어야지.","JPN":"リーダーになりたいならリーダーらしくしろ。","ENG":"If you want to be a leader, start acting like one.","TWN":"想當隊長，就得有隊長的樣子。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"비겁해요. 개차반처럼 사는 인간이 왜 이럴 때만 멀쩡한 말을 해요?","JPN":"卑怯だわ。クズのように生きてる人間がどうしてこんな時だけまともなこと言うの？","ENG":"It's not fair. You can't just suddenly act all normal when you always live like trash.","TWN":"你這卑鄙的傢伙，明明活得像狗大便一樣，為什麼每當這種時候都能說出一番大道理？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"억울하면 알아서 잘하지 그랬냐? 응? 응? 으응~?","JPN":"悔しかったら、ちゃんとやればよかっただろ～な？　な？　なあ～？","ENG":"Should've made better decisions, then. Hmm? Hmmmm?","TWN":"誰叫你要這樣，難道不是嗎？嗯？嗯～？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"咳……！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"두 사람, 잠시 시간 좀 내 주겠나?","JPN":"二人とも、少しいいかな？","ENG":"You two. May I speak to you for a minute?","TWN":"你們二位，能聽我說幾句嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"갑자기 왜? 실적 부진으로 자르려고?","JPN":"いきなりどうしたんだ？　業績不振でクビにするとか？","ENG":"What? Are you firing us for poor performance?","TWN":"什麼事？因為比賽成績不好想解雇我們？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하하, 그럴 리가. 직원들이 늘 잘해 주길 바라는 것도 욕심이지.","JPN":"はは、そんな。社員が常にうまくやることを願うのは欲深いことさ。","ENG":"Ha ha, of course not. It would be greedy of me to expect my employees to excel all the time.","TWN":"哈哈，怎麼可能。希望員工們一直有出色的表現根本是太貪心。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"잠시 지하실로 가지. 두 사람에게 보여 줄 것이 있다네.","JPN":"地下室に行こう。二人に見せたいものがあるんだ。","ENG":"Let us head to the basement. I have something to show you two.","TWN":"跟我來一趟地下室吧。我有東西要給你們看。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아, 사장님. 마침 잘 왔어. 노엘 차례는 거의 끝나가거든.","JPN":"あ、社長。ちょうどよかった。ノエルの番がもうすぐ終わるところだったんだ。","ENG":"Oh, Boss. Glad you're here. Noelle is almost done with her turn.","TWN":"喔，老闆，你來得正好，洛艾兒的部分差不多結束了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저기 쌓인 기계들은… 청소할 때 쳐들어왔던 로봇들인가?","JPN":"あっちに積もってる機械……掃除するときに攻め込んできたロボットなのか？","ENG":"Those machines... Are they the robots that invaded us when we were cleaning?","TWN":"這些機器……打掃時攻擊我們的機器人？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그런데 얼빵이가 뒤집어쓴 헬멧은 뭐야?","JPN":"それより、間抜けが被ってるヘルメットは何だよ。","ENG":"What's that weird helmet that goon is wearing?","TWN":"不過小瓜呆戴著的頭盔又是什麼？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그냥 봤을 때는…. 훈련장에 있는 시뮬레이션 장치랑 비슷하게 생겼어요.","JPN":"パッと見た感じでは……訓練場にあるシミュレーション装置と似てるわね。","ENG":"It looks like... the simulation machines at the training center.","TWN":"猛一看……好像和訓練場裡的模擬裝置差不多。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"엄마야아! 쏘지 마세요! 항복! 항복!","JPN":"いやああ！　撃たないで！　降参！　降参です！","ENG":"Whoaaa! Don't shoot! I surrender! SURRENDER!","TWN":"媽啊！別開槍！我投降！我投降！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"자, 체험 종료. 접속 끊을 테니까 조금만 기다려.","JPN":"はい、体験終了。接続切るから、ちょっとだけ待ってて。","ENG":"Now, now. Fun time's over. Hold on for a minute, I'll disconnect you.","TWN":"好，體驗結束。我會切斷連線，你等一下。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으…. 마지막엔 정말 죽는 줄 알았어요.","JPN":"うう……最後には本当に死ぬかと思いました。","ENG":"Ugh... I thought I was going to die for real.","TWN":"嗚嗚……我還以為自己真的死定了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그래도 현장감이 굉장해요! 꼭 진짜 싸우는 것 같았어요!","JPN":"でも、臨場感がすごいです！　まるで本当に戦ってるみたいでしたよ！","ENG":"It feels so real, though! I thought it was like an actual battle!","TWN":"不過臨場感超棒的！就像真的在作戰一樣！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그렇다는데요. 작동은 성공적이네요, 사장님.","JPN":"ですって。作動は成功ですね、社長。","ENG":"So it does. Looks like it's working great, Boss.","TWN":"看來啟動成功了呢，老闆。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"사장님, 이건……","JPN":"社長、これは……","ENG":"Boss, this is...","TWN":"老闆，這是……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"저돌적인 건 펜릴 소대의 특징이지. ","JPN":"猪突猛進なのはフェンリル小隊の特徴なんだ。 ","ENG":"Aggressiveness is Fenrir Squad's characteristic.","TWN":"衝動是芬里爾小隊的特色。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"자네들과 어울리란 법은 없어.","JPN":"君たちに合わないのも無理はない。","ENG":"That doesn't mean that it will suit you as well.","TWN":"並不適合你們。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……어, 어떻게 알았어요?","JPN":"……な、なんでわかったんですか？","ENG":"...H-how did you know?","TWN":"……你，你是怎麼知道的？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"우리 회사 사람들은 전부 경기를 보고 바로 알아챘을 거야.","JPN":"うちの会社の人なら試合を見てすぐ気付いたはずだよ。","ENG":"Everyone at our company would have noticed, had they been watching.","TWN":"只要是我們公司的人，看完比賽影片就可以馬上發現。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"미리 말해 두는데, 소대장 방식은 따라해서 좋을 거 없어. 조금만 삐끗해도 죽을 수 있으니까.","JPN":"あらかじめ言っておくけど、ヒルデ小隊長のやり方は真似しないこと。下手したら死ぬ可能性があるから。","ENG":"Let me tell you in advance. You shouldn't mimic Commander Hilde's combat style. One mistake and you'll be dead.","TWN":"我先提醒你，模仿希爾德小隊長的方式沒什麼好處。一不小心，你可能會死。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하지만……!","JPN":"でも……！","ENG":"But…!","TWN":"可是……！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그럼 어떻게 본선에 올라가요? 어떻게 결승까지 올라가냐구요?","JPN":"じゃあ、どうやったら本戦に出られるんですか？　どうやって決勝まで行ったらいいんですか？","ENG":"But how else can we make it past the qualifiers? How will we get to the finals, even?","TWN":"那我們要怎樣才能通過預賽？之後呢，決賽又怎麼辦？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"당신들처럼 강한 사람들에게는 쉽겠죠.","JPN":"あなたたちのような強い人には簡単でしょう。","ENG":"It's easy for people as strong as you.","TWN":"對你們這些很強的人來說或許很容易。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하지만 저에게 워치처럼 편리한 물건은 없어요. 있는 거라곤 이 방패뿐이에요.","JPN":"でも、私にはウォッチのような便利グッズはないんです。持っているものと言えばこの盾ひとつです。","ENG":"But unlike you, I don't have something as convenient as a Watch. All I have is this shield.","TWN":"可是我沒有能量環那種酷東西，我就只有這個盾牌。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그래서…… 강한 사람들이 싸우는 방식을 따라했던 거라구요.","JPN":"だから……強い人の戦い方を真似したのに。","ENG":"That's why... I mimicked how you all fought.","TWN":"所以……我才會模仿你們的作戰方式。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그런데 이렇게 져 버리면…… 카운터가 있는 팀에게는 필패일 거 아니냐구요!","JPN":"こうやって負けてしまうなら……カウンターのいるチームには絶対勝てるわけないじゃないですか！","ENG":"But... If we lose like this, we won't stand a chance against a team with Counters!","TWN":"可是輸給那種隊伍的話……就表示對方有制裁者的話根本必輸無疑吧！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"카운터는 너희 팀에도 있었어.","JPN":"カウンターならあなたたちのチームにもいたでしょ。","ENG":"Don't forget, you also had a Counter in your team.","TWN":"你們的隊伍裡也有制裁者。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘은 싸울 줄 몰라요. 일반인인 저보다 체력도 약하구요.","JPN":"ノエルさんは戦い方をわかっていません。一般人である私より体力も足りないですし。","ENG":"Noelle doesn't know how to fight. She's weaker than me, a non-Counter.","TWN":"洛艾兒不會戰鬥，體力比我這個一般人還差。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나름대로 재능은 있는 편이야. 3종 침식체에게 기습당한 용병들을 혼자 구출해냈으니까.","JPN":"それなりに才能はある方だよ。第3種侵食体に奇襲された傭兵たちを一人で助けたんだから。","ENG":"She's kind of talented, in fact. Noelle rescued a bunch of mercenaries who were attacked by a Category 3 C.O. on her own.","TWN":"她其實蠻有天分的，以前還曾經獨自救出被3類侵蝕體攻擊的傭兵。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"3종에게서요? 노엘이……?","JPN":"第3種からですか？　ノエルさんが……？","ENG":"From a Category 3? That Noelle...?","TWN":"3類侵蝕體嗎？洛艾兒……？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"에헤헤, 사장님의 지시 덕분이지만요.","JPN":"えへへ、社長が指示してくれたおかげですけどね。","ENG":"Eh he he, it's all thanks to Boss's orders.","TWN":"嘿嘿嘿，都是老闆的指示下得好。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저 혼자선 허둥거리기만 하다 당했을 거예요.","JPN":"私一人だったら、慌てるばかりでやられていたはずです。","ENG":"If I did it alone, I would've died hesitating.","TWN":"如果是我自己，可能只會手忙腳亂。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"헤에…. 그렇단 말이지. 의외네.","JPN":"へえ……なるほど。意外だな。","ENG":"Huh, I see... How unexpected.","TWN":"欸……真的嗎？真是意外。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"세 사람 다 역량은 충분하다고 생각해.","JPN":"三人とも、力量は十分あると思う。","ENG":"All three of you have potential.","TWN":"我認為你們三個人的能力都足夠。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"남은 건 실전에서 어떻게 싸우느냐지.","JPN":"後は実戦でどう戦うかだね。","ENG":"How you utilize it in battle is what matters the most.","TWN":"剩下的就只是學習如何在實戰中應用。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"잠깐만요. 그럼 이 장치는…….","JPN":"ちょっと待ってください。それじゃあ、この装置は……","ENG":"Wait, then this machine is...","TWN":"等等，那這個裝置是……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그래. 사장님이 너희들 때문에 준비한 시뮬레이터야.","JPN":"そう。社長があなたたちのために準備したシミュレーターよ。","ENG":"Yeah. It's a simulator that Boss prepared for you.","TWN":"沒錯，這是老闆為你們準備的模擬器。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우리 사장 본업이 산타 할아버지였나? 드디어 착하게 살아 온 상을 받는 건가?","JPN":"社長の本業ってサンタだったのか？　やっと真面目に生きてきたご褒美をもらえる時が来たのか？","ENG":"Boss, are you actually Santa Claus? Is this my reward for being a good person?","TWN":"哇！老闆你的本業是聖誕老人嗎？這是我很乖的禮物嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……공짜로 이런 걸 주는 사람은 세상에 없어요.","JPN":"……タダでこんなものをくれる人なんて、この世にいるわけないわ。","ENG":"...There's no such thing as a free lunch, Laika.","TWN":"……這個世界上沒有白吃的午餐。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저희에게 원하는 게 있는 거죠?","JPN":"何か交換条件があるんでしょう？","ENG":"You must want something from us, don't you?","TWN":"你想從我們這裡得到什麼？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"결승 진출이라고 하면 믿겠나?","JPN":"決勝進出と言えば信じてくれるかな？","ENG":"Would you believe me if I said I want to see you make it to the finals?","TWN":"如果我說想讓你們打入決賽，你相信嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"거짓말…… 그런 대답은 아무나 데려와도 할 수 있을 걸요.","JPN":"ウソ……そんな答えは誰でもできます。","ENG":"Liar... Anyone can say that.","TWN":"騙人……那種冠冕堂皇的話誰都會說。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너 어린 거 아니까 고집 적당히 부려.","JPN":"ガキなのは知ってるけど、意地張るのもいい加減にしろよ。","ENG":"Yeah, yeah. We all know you're a kid, stop acting so stubborn.","TWN":"年紀輕輕的別那麼固執。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시즌 개막하기 전에 네 입으로 말했잖아.","JPN":"シーズンの開幕前に、自分で言っただろ？","ENG":"You said so yourself, before the season started.","TWN":"賽季開幕之前你不是還打包票？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"경기 성적이 안 좋으면 사장더러 마음대로 하라고.","JPN":"試合の成績が悪かったら社長の勝手にしろって。","ENG":"That Boss is free to do whatever he wants if we don't perform well.","TWN":"說如果比賽成績不好，就任由老闆處置。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그, 그건 그냥…….","JPN":"そ、それはただ……","ENG":"Th-that was just a...","TWN":"那，那是……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어떡하냐. 너 이제 큰일났다, 꼬맹아. 팔려가는 건 내가 아니라 네가 되겠네.","JPN":"どうする？　こりゃ大変だ。売られていくのは私じゃなくてあんたになりそうだな。","ENG":"You're in trouble now, kid. It's you who's gonna be sold off to some bar, not me.","TWN":"怎麼辦呢？糟糕囉，看來會被賣去奇怪酒吧的人是你，不是我。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"누구 편이에요, 라이카는 대체!","JPN":"ライカはいったい誰の味方なの！","ENG":"Whose side are you on, Laika?!","TWN":"你到底跟誰是一國的，萊卡！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"자, 자. 잡담은 나중에. 우선 테스트부터 끝내자.","JPN":"はい、はい。無駄話は後でね。まずはテストから済ませましょう。","ENG":"Now, now. Enough with the chit-chat. Let's finish the tests first.","TWN":"好了，好了，以後再鬥嘴吧。先來完成測試。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어떻게 쓰면 되는지는 제가 가르쳐 드릴게요. 테스트하면서 여러 번 써 봤거든요.","JPN":"どう使ったらいいのかは私が教えますね。テストしながら何度も使ってみましたから。","ENG":"I'll show you how to put them on. I had to do it a lot while testing.","TWN":"我來跟你們說怎麼用，測試的時候我已經用過好幾次了呢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐 해. 얼른 준비 안 하고. 너도 쟤한테서 얼빵한 게 옮았냐?","JPN":"何してんだ。早く準備しろよ。あいつから間抜けが移ったのか？","ENG":"What's up, slowpoke? Caught stupidity from that goon or something?","TWN":"在幹什麼呢，還不快準備？你也被她傳染小瓜呆病了嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이익!","JPN":"ぐぐっ！","ENG":"Ugh!","TWN":"哼！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"악!! 정강이 까지 마, 이 미친 꼬맹아!","JPN":"うわっ！！　向う脛蹴るな、このクソガキ！","ENG":"Aah! Don't kick me, you psycho!","TWN":"哎喔！！幹嘛踢我小腿，你這個小瘋子！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L13_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"다들 준비됐지? 그럼 시작한다?","JPN":"みんな、準備はできたよね？　じゃあ、始めるよ？","ENG":"Are we all ready? Let's start, okay?","TWN":"大家都準備好了吧？那我就開始囉？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"여기는…. 이게 정말 시뮬레이터예요?","JPN":"ここは……これ、本当にシミュレーターなんですか？","ENG":"This place... Is this really a simulation?","TWN":"這裡是……這個真的是模擬器嗎？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"일단은 그런가 봐.","JPN":"一応はそうみたいだな。","ENG":"I guess so.","TWN":"好像是。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"문제는 얼빵이가 안 보이는데…….","JPN":"問題は、間抜けが見えないってことだけど……","ENG":"I don't see that goon for some reason, though...","TWN":"問題是小瓜呆人呢……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트! 라이카 씨!","JPN":"フェリセット！　ライカさん！","ENG":"Félicette! Laika!","TWN":"費莉塞特！萊卡！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아, 저기 있다.","JPN":"あ、あそこだ。","ENG":"Oh, there she is.","TWN":"喔，在那裡。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그런데 표정이 좀… 이상한데요?","JPN":"でも、表情がちょっと……おかしいわ。","ENG":"She looks a little... strange.","TWN":"不過表情有點……奇怪？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"거기 계시면 안 돼요! 얼른 도망──","JPN":"そこにいちゃダメです！　早く逃げ――","ENG":"You shouldn't stay there! Run for your l–","TWN":"不可以待在那裡！快跑——"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"하하핫! 여기 있었구나! 쥐새끼들아!","JPN":"ハハハ！　ここにいたのか！　ネズミども！","ENG":"Hahahaha! There you are! You little rats!","TWN":"哈哈哈！原來在這裡！這些鼠輩！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭐, 뭐예요? 저 여자는? 노엘을 완전히 짓밟아 버렸어…!","JPN":"な、何なの？　あの女？　ノエルさんを完全に踏みつぶした……！","ENG":"W-what is that? Who is that woman? She crushed Noelle...!","TWN":"什，什麼？那女人是？洛艾兒被踩扁咧……！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으갸윽!?","JPN":"うぎゃあっ！？","ENG":"Kyyahh?!","TWN":"哎呀呀！？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘! 살아 있었어요?","JPN":"ノエルさん！　生きてたんですか？","ENG":"Noelle! Are you okay?","TWN":"洛艾兒！你還活著嗎？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"당연하죠! 저 노엘, 이 공간에서만큼은 역전의 용사입니다!","JPN":"当たり前です！　このノエル、この空間でだけは歴戦の勇者です！","ENG":"Of course! In here, I'm Noelle, the great veteran!","TWN":"那當然！我洛艾兒，在這個空間裡可是逆轉的勇士！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"처음 일곱 번은 얼굴에 신발 자국이 나면서 접속이 끊겼지만요….","JPN":"最初の7回は顔に靴の跡がついて接続が切れちゃったんですけど……","ENG":"Although I did get disconnected with a foot mark on my face for the first seven times...","TWN":"雖然剛開始的七次都是臉上帶著鞋印切斷連線的……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이야, 그 말 들으니까 확실히 위험한 상대라는 느낌이 팍팍 드는데.","JPN":"いやあ、それを聞くと確かに危ない相手だって感じがビンビンするな。","ENG":"Man, looks like our opponent isn't an easy one at all, eh?","TWN":"聽你這麼說，感覺確實是個危險的對手。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"두 사람 다 제 뒤로 붙으세요.","JPN":"二人とも私の後ろに入ってください。","ENG":"Both of you, fall back. Behind me.","TWN":"你們二個都躲到我後面。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"제 방패라면 최소한 공격을 못 받아내진 않을 거예요.","JPN":"私の盾なら最低でも攻撃を止めることはできるはずよ。","ENG":"My shield should be able to block her attacks.","TWN":"我的盾牌應該可以擋下基本的攻擊。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"흥…. 시뮬레이션 주제에 진지하게 만드네.","JPN":"フン……シミュレーションなんかにマジにさせられるなんてな。","ENG":"Hmph... We're getting awfully serious for a simulation.","TWN":"哼……模擬而已，搞得那麼認真。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"얼빵이! 우리 중 화력은 네가 제일이야! 절대 저 녀석 공격에 휘말리지 마!","JPN":"間抜け！　私たちの中であんたの火力が一番なんだ！　あいつの攻撃に絶対振り回されるなよ！","ENG":"Hey, goon! You have the best firepower among us! Don't you dare get caught up in her attack!","TWN":"小瓜呆！我們之中你的火力最強！千萬別被那傢伙的攻擊牽著鼻子走！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네! 명심하겠습니다!","JPN":"はい！　了解です！","ENG":"Yes, ma'am! Got it!","TWN":"是！我知道了！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};